mapper.select:
      /* com.kdt.pjt_pjt.mapper.pjt_mng.PjtMngMapper.selectProjectList*/
SELECT B.PJT_SN,
	  B.PJT_NM,
     B.PJT_STTS_CD,
      B.employeeId,
       B.FRST_REG_DT, B.LAST_MDFCN_DT,
       B.PJT_BGNG_DT, B.PJT_END_DT, B.TB_PJT_APR, B.ver
FROM VIEW_PJT_BASC B
WHERE (B.USE_YN IS NULL OR B.USE_YN = 'Y')

    AND B.company_id = #{companyId}


    AND (B.PJT_NM LIKE CONCAT('%', #{keyword}, '%')
         OR B.employeeId LIKE CONCAT('%', #{keyword}, '%'))


    AND B.employeeId = #{employeeId}


    AND B.TB_PJT_APR = #{employeeId}

ORDER BY B.LAST_MDFCN_DT DESC, B.PJT_SN DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM VIEW_PJT_BASC B
WHERE (B.USE_YN IS NULL OR B.USE_YN = 'Y')

    AND B.company_id = #{companyId}


    AND (B.PJT_NM LIKE CONCAT('%', #{keyword}, '%')
         OR B.employeeId LIKE CONCAT('%', #{keyword}, '%'))


    AND B.employeeId = #{employeeId}


    AND B.TB_PJT_APR = #{employeeId}

/* com.kdt.pjt_pjt.mapper.pjt_mng.PjtMngMapper  */
  SELECT COUNT(*)
  FROM VIEW_PJT_BASC
  WHERE (USE_YN IS NULL OR USE_YN = 'Y')
    AND employeeId = #{employeeId}

/* searchProjectMngList */
select t2.PJT_SN , t2.PJT_NM , t2.PJT_STTS_CD , ( SELECT emp_nm from employee where 1=1 and employeeId = t2.employeeId ) AS employeeId , ( SELECT position from employee where 1=1 and employeeId = t2.employeeId ) AS position , t2.USE_YN , t2.FRST_REG_DT , t2.LAST_MDFR_ID , t2.PJT_BGNG_DT , t2.PJT_END_DT , ( SELECT emp_nm from employee where 1=1 and employeeId = t2.TB_PJT_APR ) AS TB_PJT_APR , ( SELECT position from employee where 1=1 and employeeId = t2.TB_PJT_APR ) AS position_APR , t2.TB_PJT_BASCcol , t2.docType , t2.content , t2.ATCH_FILE_SN1 , t2.ORG_FILE_NM1 , t2.ATCH_FILE_SN2 , t2.ATCH_FILE_SN3 , t2.ORG_FILE_NM2 , t2.ORG_FILE_NM3 , t2.TB_PJT_BASCcol1 , t2.gid , t2.ver , t2.firstSign , t2.secondSign , t2.approvedBy
from TB_PJT_BASC t2, (select gid, max(ver) as max_ver from TB_PJT_BASC group by gid) t1 where t2.gid = t1.gid and t2.ver = t1.max_ver and (t2.USE_YN IS NULL OR t2.USE_YN = 'Y')
AND t2.company_id = #{companyId}
AND (t2.PJT_NM LIKE CONCAT('%', #{keyword}, '%') OR t2.employeeId = #{keyword})
ORDER BY t2.FRST_REG_DT DESC

SELECT t2.PJT_SN , t2.PJT_NM , t2.PJT_STTS_CD , ( SELECT emp_nm from employee where 1=1 and employeeId = t2.employeeId ) AS employeeId , ( SELECT position from employee where 1=1 and employeeId = t2.employeeId ) AS position , t2.USE_YN , t2.FRST_REG_DT , t2.LAST_MDFR_ID , t2.PJT_BGNG_DT , t2.PJT_END_DT , ( SELECT emp_nm from employee where 1=1 and employeeId = t2.TB_PJT_APR ) AS TB_PJT_APR , ( SELECT position from employee where 1=1 and employeeId = t2.TB_PJT_APR ) AS position_APR , t2.TB_PJT_BASCcol , t2.docType , t2.content , t2.ATCH_FILE_SN1 , t2.ORG_FILE_NM1 , t2.ATCH_FILE_SN2 , t2.ATCH_FILE_SN3 , t2.ORG_FILE_NM2 , t2.ORG_FILE_NM3 , t2.TB_PJT_BASCcol1 , t2.gid , t2.ver , t2.firstSign , t2.secondSign , t2.approvedBy FROM VIEW_PJT_BASC t2 WHERE TB_PJT_APR = #{employeeId}
AND t2.company_id = #{companyId}
AND (PJT_NM LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY FRST_REG_DT DESC

SELECT COALESCE(MAX(ver), 0)
FROM TB_PJT_BASC
WHERE pjt_sn = #{pjtSn}
